/**
 * MockCall - Mock 通话页面容器
 *
 * 参考 VideoCall/index.tsx 结构：
 * - 进入页面时开启本地摄像头（由 MockCallView 处理）
 * - 挂断时调用 mockCallManager.endMockCall()
 * - 导航回 /live
 * - 接入 ExitCallModal 弹窗逻辑（与 VideoCall 一致）
 */

import { useCallback, useEffect, useRef } from "react";
import { useNavigate } from "react-router-dom";
import MockCallView from "@/pages/MockCall/MockCallView";
import LiveRoomTopPanel from "@/components/LiveRoomTopPanel";
import mockCallManager from "@/utils/mockCallManager";
import { MockCallState } from "@/types/call";
import { showExitCallModal } from "@/components/ExitCallModal";
import { getReturnPath } from "@/utils/callReturnPath";
import { bpTrack } from "@/tracking";
import { EventName } from "@/tracking/events";
import { STORAGE_KEYS } from "@/constants/storageKeys";

const MockCall = () => {
  const navigate = useNavigate();

  const pageStartTime = useRef(Date.now());
  const is15HintShown = useRef(false);
  const is30HintShown = useRef(false);

  /** 获取当前通话时长（秒） */
  const getCallDuration = useCallback(() => {
    const session = mockCallManager.connectSession;
    if (!session?.callBeginTime) return 0;
    return Math.round((Date.now() - session.callBeginTime) / 1000);
  }, []);

  /** 获取倒计时时间（页面打开后 5 秒内不允许挂断） */
  const getCountdownTime = useCallback(() => {
    const elapsed = Math.round((Date.now() - pageStartTime.current) / 1000);
    return Math.max(0, 5 - elapsed);
  }, []);

  /** 执行挂断并返回 */
  const handleHangup = useCallback(() => {
    // 埋点：确认结束通话
    const count = Number(localStorage.getItem(STORAGE_KEYS.STAGE_TWO_MOCK_COUNT) || "0");
    if (count === 0) {
      bpTrack(EventName.pwa_conv_call1_end_confirm);
    } else {
      bpTrack(EventName.pwa_conv_call2_end_confirm);
    }
    mockCallManager.endMockCall();
    navigate(getReturnPath(), { replace: true });
  }, [navigate]);

  /** 继续通话 */
  const handleContinue = useCallback(() => {
    is30HintShown.current = false;
    is15HintShown.current = false;
  }, []);

  // ==================== 主入口：点击关闭按钮 ====================

  const handleClose = useCallback(() => {
    const duration = getCallDuration();

    // 埋点：点击结束通话按钮
    const count = Number(localStorage.getItem(STORAGE_KEYS.STAGE_TWO_MOCK_COUNT) || "0");
    if (count === 0) {
      bpTrack(EventName.pwa_conv_call1_end_click);
    } else {
      bpTrack(EventName.pwa_conv_call2_end_click);
    }

    // 通话 ≤ 28s → 15秒违规警告
    if (duration <= 28 && !is15HintShown.current) {
      is15HintShown.current = true;
      showExitCallModal({
        isUserHangup: true,
        is30Hint: false,
        is15Hint: true,
        callTypeLabel: "video",
        countdownTime: getCountdownTime(),
        onEndCall: handleHangup,
        onContinue: handleContinue,
      });
      return;
    }

    // 28s < 通话 < 30s → 30秒挽留
    if (duration > 28 && duration < 30 && !is30HintShown.current) {
      is30HintShown.current = true;
      showExitCallModal({
        isUserHangup: true,
        is30Hint: true,
        is15Hint: false,
        callTypeLabel: "video",
        countdownTime: getCountdownTime(),
        onEndCall: handleHangup,
        onContinue: handleContinue,
      });
      return;
    }

    // 兜底 → 普通确认挂断
    showExitCallModal({
      isUserHangup: true,
      is30Hint: false,
      is15Hint: false,
      callTypeLabel: "video",
      countdownTime: getCountdownTime(),
      onEndCall: handleHangup,
      onContinue: handleContinue,
    });
  }, [getCallDuration, getCountdownTime, handleHangup, handleContinue]);

  // ==================== 生命周期 ====================

  useEffect(() => {
    const connectSession = mockCallManager.connectSession;
    if (
      !connectSession ||
      connectSession.callState === MockCallState.Idle ||
      connectSession.callState === MockCallState.Ended
    ) {
      navigate(getReturnPath(), { replace: true });
    }
  }, [navigate]);

  useEffect(() => {
    return () => {
      const connectSession = mockCallManager.connectSession;
      if (
        connectSession &&
        (connectSession.callState === MockCallState.Connecting || connectSession.callState === MockCallState.Connected)
      ) {
        mockCallManager.endMockCall();
      }
    };
  }, []);

  const mockVideoUrl = mockCallManager.connectSession?.mockVideoUrl;
  if (!mockVideoUrl) {
    return null;
  }

  return (
    <div className="fixed inset-0 bg-black">
      <MockCallView mockVideoUrl={mockVideoUrl} />
      <LiveRoomTopPanel onClickClose={handleClose} isAlwaysShow={true} />
    </div>
  );
};

export default MockCall;
